const subject = $json.subject || $json.Subject || '';
const body = $json.email_body_clean || $json.snippet || $json.textPlain || '';
const text = `${subject}\n${body}`;

const redFlagKeywords = [
  "簡単",
  "誰でもできます",
  "初心者歓迎",
  "修正無制限",
  "納得いくまで",
  "いい感じに",
  "丸投げ",
  "格安",
  "予算がありません",
  "本日中",
  "明日まで",
  "急ぎ",
  "成果報酬",
  "まずは低単価",
  "継続前提",
  "テストで安く",
  "無料で",
  "サンプルとして"
];

const matched = redFlagKeywords.filter(word => text.includes(word));

const riskRules = [
  {
    pattern: /修正無制限|納得いくまで/g,
    points: 30,
    reason: "修正範囲が膨らむ可能性"
  },
  {
    pattern: /本日中|明日まで|急ぎ|即日/g,
    points: 20,
    reason: "納期が短い"
  },
  {
    pattern: /格安|予算がありません|無料で|低単価/g,
    points: 25,
    reason: "報酬条件が弱い"
  },
  {
    pattern: /いい感じに|丸投げ|お任せ/g,
    points: 20,
    reason: "要件が曖昧"
  },
  {
    pattern: /成果報酬/g,
    points: 20,
    reason: "成果条件が不明確"
  },
  {
    pattern: /初心者歓迎|誰でもできます|簡単/g,
    points: 15,
    reason: "低単価案件の可能性"
  }
];

let keywordRiskScore = 0;
const redFlagReasons = [];

for (const rule of riskRules) {
  if (rule.pattern.test(text)) {
    keywordRiskScore += rule.points;
    redFlagReasons.push(rule.reason);
  }
}

keywordRiskScore = Math.min(keywordRiskScore, 100);

return {
  ...$json,
  subject_normalized: subject,
  body_normalized: body,
  red_flags_keyword: matched,
  red_flag_reasons_keyword: [...new Set(redFlagReasons)],
  keyword_risk_score: keywordRiskScore
};

