// Add a new field called 'myNewField' to the JSON of the item
const j = $json;

function pick(...values) {
  return values.find(v => v !== undefined && v !== null && String(v).trim() !== '') || '';
}

const subject = pick(j.subject, j.Subject);
const fromRaw = pick(j.from, j.From, j.sender);
const textPlain = pick(j.textPlain, j.text, j.body?.text, j.snippet);
const html = pick(j.textHtml, j.html, j.body?.html);
const bodyRaw = textPlain || html.replace(/<[^>]*>/g, ' ');

const cleanBody = bodyRaw
  .replace(/\r/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .replace(/On .* wrote:/gi, '')
  .replace(/-----Original Message-----[\s\S]*/gi, '')
  .replace(/--\s*\n[\s\S]*/g, '')
  .trim();

let sourcePlatform = 'direct';
const combined = `${subject}\n${fromRaw}\n${cleanBody}`.toLowerCase();

if (combined.includes('lancers') || combined.includes('ランサーズ')) {
  sourcePlatform = 'lancers';
} else if (combined.includes('crowdworks') || combined.includes('クラウドワークス')) {
  sourcePlatform = 'crowdworks';
} else if (combined.includes('coconala') || combined.includes('ココナラ')) {
  sourcePlatform = 'coconala';
} else if (combined.includes('wantedly')) {
  sourcePlatform = 'wantedly';
}

return {
  ...j,
  message_id: pick(j.id, j.messageId),
  thread_id: pick(j.threadId, j.thread_id),
  subject,
  from_raw: fromRaw,
  email_body_clean: cleanBody,
  source_platform_detected: sourcePlatform,
  received_at: new Date().toISOString()
};

const geminiOutput = $json;

function findText(obj) {
  if (!obj) return '';

  if (typeof obj === 'string') return obj;

  const candidates = [
    obj.text,
    obj.output,
    obj.response,
    obj.content,
    obj.message,
    obj.candidates?.[0]?.content?.parts?.[0]?.text,
    obj.candidates?.[0]?.content?.text,
    obj.parts?.[0]?.text
  ];

  for (const c of candidates) {
    if (typeof c === 'string' && c.trim()) return c;
  }

  return JSON.stringify(obj);
}

function extractJson(raw) {
  const text = findText(raw)
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');

  if (start === -1 || end === -1) {
    throw new Error('Gemini output does not contain valid JSON.');
  }

  return JSON.parse(text.slice(start, end + 1));
}

const ai = extractJson(geminiOutput);

const original = $('Code: Detect Japanese red flags').first().json;
const config = $('Set config: Freelancer settings').first().json;

const keywordRiskScore = Number(original.keyword_risk_score || 0);
const aiRiskScore = Number(ai.risk_score || 0);
const riskScore = Math.min(100, Math.max(aiRiskScore, keywordRiskScore));

const scopeClarity = Number(ai.scope_clarity_score || 0);
const matchScore = Number(ai.match_score || 0);
const portfolioScore = Number(ai.portfolio_value_score || 0);

const finalScore =
  matchScore * 0.30 +
  portfolioScore * 0.20 +
  scopeClarity * 0.20 -
  riskScore * 0.30;

let decision = ai.decision || 'hold';

if (riskScore >= 70) {
  decision = 'decline';
} else if (finalScore >= 70 && riskScore < 50 && scopeClarity >= 60) {
  decision = 'accept';
} else if (finalScore >= 40) {
  decision = 'hold';
} else {
  decision = 'decline';
}

const estimatedMin = Math.max(1, Number(ai.estimated_hours_min || 1));
const estimatedMax = Math.max(estimatedMin, Number(ai.estimated_hours_max || estimatedMin + 1));

let recommendedPrice = Number(ai.recommended_price_jpy || 0);
const hourlyRate = Number(config.hourly_rate_jpy || 3000);
const minimumFee = Number(config.minimum_project_fee_jpy || 10000);

const minimumByHours = Math.ceil(estimatedMax * hourlyRate);

recommendedPrice = Math.max(
  recommendedPrice,
  minimumByHours,
  minimumFee
);

const safeTitle = String(
  ai.project_title ||
  original.subject_normalized ||
  original.subject ||
  original.Subject ||
  'Untitled side gig'
)
  .replace(/[\\/:*?"<>|]/g, '')
  .slice(0, 80);

const now = new Date();
const projectId = `SG-${now.toISOString().slice(0, 10).replace(/-/g, '')}-${Math.random().toString(36).slice(2, 7).toUpperCase()}`;
return {
  ...original,

  project_id: projectId,
  project_title: safeTitle,
  source_platform: ai.source_platform || original.source_platform_detected || 'direct',
  project_category: ai.project_category || '',
  client_goal: ai.client_goal || '',
  deliverables: ai.deliverables || [],
  scope_summary: ai.scope_summary || '',
  out_of_scope: ai.out_of_scope || [],
  budget_text: ai.budget_text || '',
  deadline_text: ai.deadline_text || '',

  estimated_hours_min: estimatedMin,
  estimated_hours_max: estimatedMax,
  recommended_price_jpy: recommendedPrice,
  recommended_deadline_days: Math.max(1, Number(ai.recommended_deadline_days || 3)),

  scope_clarity_score: scopeClarity,
  risk_score: riskScore,
  portfolio_value_score: portfolioScore,
  match_score: matchScore,
  final_score: Math.round(finalScore),

  decision,
  decision_reason: ai.decision_reason || '',

  red_flags: Array.from(new Set([
    ...(original.red_flags_keyword || []),
    ...(ai.red_flags || [])
  ])),

  clarifying_questions: ai.clarifying_questions || [],
  reply_draft: ai.reply_draft || '',
  decline_draft: ai.decline_draft || '',
  next_tasks: ai.next_tasks || [],
  delivery_checklist: ai.delivery_checklist || [],
  portfolio_memo_seed: ai.portfolio_memo_seed || {},

  status:
    decision === 'accept'
      ? '提案準備'
      : decision === 'hold'
        ? '確認待ち'
        : '辞退候補'
};

const j = $('Switch: Route by decision').first().json;
const folder = $json;

function list(arr) {
  if (!arr || !arr.length) return '- なし';
  return arr.map(v => `- ${v}`).join('\n');
}

