const p = j.portfolio_memo_seed || {};

const portfolioBody = `# 実績化メモ：${j.project_title}

## 案件概要
${p.project_summary || j.client_goal || ''}

## 使用ツール
${list(p.tools_used || [])}

## 納品物
${list(p.deliverables_for_portfolio || j.deliverables || [])}

## 工夫した点
- 

