${p.portfolio_publishability || 'unknown'}

## 次に使い回せる要素
${list(p.future_reuse_ideas || [])}

## 次回改善
- 
`;

return {
  ...j,
  drive_folder_id: folder.id || folder.fileId || '',
  drive_folder_url: folder.webViewLink || '',
  scope_doc_title: `${j.project_id}_scope_lock_${j.project_title}`,
  checklist_doc_title: `${j.project_id}_delivery_checklist_${j.project_title}`,
